parameters.jsCode:
try {
  const content = $json.candidates[0].content.parts[0].text;
  const jsonMatch = content.match(/\[[\s\S]*\]/);
  const jsonStr = jsonMatch ? jsonMatch[0] : "[]";
  const result = JSON.parse(jsonStr);
  const domain = $("Seleccionar Empresa").first().json.domain;
  const companyName = $("Seleccionar Empresa").first().json.name;
  return result.map(p => ({ json: { ...p, domain, companyName } }));
} catch (e) {
  return [];
}

const existingLeads = $("Google Sheets: Leer Existentes").all();
const existingNames = existingLeads.map(l => `${l.json.Nombre} ${l.json.Apellido}`.toLowerCase().trim());
const currentBatch = $("Formatear Listado").all();

return currentBatch.filter(lead => {
  const fullName = `${lead.json.firstName} ${lead.json.lastName}`.toLowerCase().trim();
  return !existingNames.includes(fullName);
});

let email = $json.data.email;
let status = "Verificado (Hunter)";
let confidence = ($json.data.score || 0) + "%";

if (!email) {
  const p = $("Filtro: Anti-Duplicados").item.json;
  const cleanFirst = p.firstName.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/\s+/g, '');
  const cleanLast = p.lastName.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/\s+/g, '');
  email = `${cleanFirst}.${cleanLast}@${p.domain}`;
  status = "Deducido (Patron AI)";
  confidence = "70% (Estimado)";
}

return {
  email,
  status,
  confidence,
  firstName: $("Filtro: Anti-Duplicados").item.json.firstName,
  lastName: $("Filtro: Anti-Duplicados").item.json.lastName,
  cargo: $("Filtro: Anti-Duplicados").item.json.cargo,
  domain: $("Filtro: Anti-Duplicados").item.json.domain,
  company: $("Filtro: Anti-Duplicados").item.json.companyName,
  linkedin: $("Filtro: Anti-Duplicados").item.json.linkedinURL
};
